@torch._inductor.config.patch("graph_partition", True)
@torch._inductor.config.patch("implicit_fallbacks", True)
def test_graph_partition_with_memory_plan_reuse(self):
    BATCH_SIZE = 16
    MLP_SIZE = 128
    HIDDEN_SIZE = 128
    RANDOM_SEED = 0

    @torch.library.custom_op(
        "silly::attention",
        mutates_args=["out"],
        tags=(torch._C.Tag.cudagraph_unsafe,),
    )
    def attention(
        q: torch.Tensor, k: torch.Tensor, v: torch.Tensor, out: torch.Tensor
    ) -> None:
        out.copy_(q + k + v)

    @attention.register_fake
    def _(q, k, v, out):
        return None

    class ParentModel(torch.nn.Module):
        def __init__(self) -> None:
            super().__init__()

        def forward(self, x: torch.Tensor) -> torch.Tensor:
            return x

    class Attention(torch.nn.Module):
        def __init__(self, mlp_size: int, hidden_size: int) -> None:
            super().__init__()
            self.pre_attn = torch.nn.Linear(mlp_size, hidden_size, bias=False)
            self.post_attn = torch.nn.Linear(hidden_size, mlp_size, bias=False)
            self.rms_norm_weight = torch.nn.Parameter(torch.ones(hidden_size))

        def rms_norm_ref(self, x: torch.Tensor) -> torch.Tensor:
            x_f32 = x.float()
            return (
                x_f32
                * torch.rsqrt(
                    torch.mean(x_f32.square(), dim=-1, keepdim=True) + 1e-6
                )
                * self.rms_norm_weight
            ).to(x.dtype)

        def forward(self, x: torch.Tensor) -> torch.Tensor:
            x = self.pre_attn(x)
            x = self.rms_norm_ref(x)
            attn_output = torch.empty_like(x)
            torch.ops.silly.attention(x, x, x, attn_output)
            x = attn_output
            x = self.rms_norm_ref(x)
            x = self.post_attn(x)
            return x

    class CompiledAttention(torch.nn.Module):
        def __init__(
            self,
            *,
            mlp_size: int,
            hidden_size: int,
        ) -> None:
            super().__init__()
            self.attn = Attention(mlp_size, hidden_size)

        def forward(self, x: torch.Tensor) -> torch.Tensor:
            return self.attn(x)

    class CompiledAttentionTwo(CompiledAttention):
        def forward(self, x: torch.Tensor) -> torch.Tensor:
            return self.attn(x)

    class AggregatedModel(torch.nn.Module):
        def __init__(self) -> None:
            super().__init__()
            self.parent_model = ParentModel()
            self.attention_1 = CompiledAttention(
                mlp_size=MLP_SIZE, hidden_size=HIDDEN_SIZE
            )
            self.attention_2 = CompiledAttentionTwo(
                mlp_size=MLP_SIZE, hidden_size=HIDDEN_SIZE
            )

        def forward(self, x: torch.Tensor) -> torch.Tensor:
            x = self.parent_model(x)
            x_1 = self.attention_1(x)
            x_2 = self.attention_2(x)
            return x_1 + x_2

    def test_memory_plan_reuse():
        model = AggregatedModel().to(device="cuda")
        model.attention_1 = torch.compile(
            model.attention_1, mode="reduce-overhead"
        )
        model.attention_2 = torch.compile(
            model.attention_2, mode="reduce-overhead"
        )
        torch.manual_seed(RANDOM_SEED)
        x = torch.randn(BATCH_SIZE, MLP_SIZE, device="cuda")
        for _ in range(3):
            model(x)

    # run twice to trigger OOM if memory is not properly managed
    # should be no op, but keep for regression.
    test_memory_plan_reuse()
    torch._dynamo.reset()
    test_memory_plan_reuse()

